"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[60080],{276:e=>{e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"defaultSidebar":[{"type":"link","href":"/NevermoreEngine/docs/intro","label":"Intro","docId":"intro","unlisted":false},{"type":"link","href":"/NevermoreEngine/docs/install","label":"Install","docId":"install","unlisted":false},{"type":"category","label":"Architecture","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/NevermoreEngine/docs/architecture/servicebag","label":"Using Services","docId":"architecture/servicebag","unlisted":false},{"type":"link","href":"/NevermoreEngine/docs/architecture/design","label":"Design","docId":"architecture/design","unlisted":false},{"type":"link","href":"/NevermoreEngine/docs/architecture/patterns","label":"Core Patterns","docId":"architecture/patterns","unlisted":false}],"href":"/NevermoreEngine/docs/architecture/"},{"type":"link","href":"/NevermoreEngine/docs/deploy","label":"Deploying with the CLI","docId":"deploy","unlisted":false},{"type":"link","href":"/NevermoreEngine/docs/cli","label":"CLI Reference","docId":"cli","unlisted":false},{"type":"link","href":"/NevermoreEngine/docs/build","label":"Contributing","docId":"build","unlisted":false},{"type":"category","label":"Testing","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/NevermoreEngine/docs/testing/","label":"Test Infrastructure","docId":"testing/testing","unlisted":false},{"type":"link","href":"/NevermoreEngine/docs/testing/integration-testing","label":"Integration Testing","docId":"testing/integration-testing","unlisted":false}],"href":"/NevermoreEngine/docs/testing/"},{"type":"category","label":"Conventions","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/NevermoreEngine/docs/conventions/luau","label":"Luau Conventions","docId":"conventions/luau","unlisted":false},{"type":"link","href":"/NevermoreEngine/docs/conventions/typescript","label":"TypeScript Conventions","docId":"conventions/typescript","unlisted":false},{"type":"link","href":"/NevermoreEngine/docs/conventions/git-workflow","label":"Git Workflow","docId":"conventions/git-workflow","unlisted":false},{"type":"link","href":"/NevermoreEngine/docs/conventions/templates","label":"Template Conventions","docId":"conventions/templates","unlisted":false}],"href":"/NevermoreEngine/docs/conventions/"},{"type":"category","label":"IDE Setup","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/NevermoreEngine/docs/ides/vscode","label":"VSCode / Cursor","docId":"ides/vscode","unlisted":false}],"href":"/NevermoreEngine/docs/ides/"},{"type":"category","label":"Gotchas","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/NevermoreEngine/docs/gotchas/tooling","label":"Tooling Gotchas","docId":"gotchas/tooling","unlisted":false},{"type":"link","href":"/NevermoreEngine/docs/gotchas/troubleshooting","label":"Troubleshooting","docId":"gotchas/troubleshooting","unlisted":false}],"href":"/NevermoreEngine/docs/gotchas/"}]},"docs":{"architecture/design":{"id":"architecture/design","title":"Design","description":"Nevermore consists of a few hundred packages in a mono-repo. These packages are semantically versioned such that long-term maintenance can be done. Nevermore is trying to provide utility modules, and is not a framework.","sidebar":"defaultSidebar"},"architecture/index":{"id":"architecture/index","title":"Architecture","description":"Nevermore\'s architecture is built around a few core ideas: services as singletons managed by a dependency injection container, and composable packages that can be combined without knowing about each other.","sidebar":"defaultSidebar"},"architecture/patterns":{"id":"architecture/patterns","title":"Core Patterns","description":"Beyond ServiceBag, Nevermore uses several patterns that appear throughout the codebase. Understanding these makes it much easier to read and write Nevermore code.","sidebar":"defaultSidebar"},"architecture/servicebag":{"id":"architecture/servicebag","title":"Using Services","description":"Services in Nevermore use ServiceBag and need to be","sidebar":"defaultSidebar"},"build":{"id":"build","title":"Contributing","description":"This document is intended to help people submit bug patches, new features, and more to Nevermore. If you would simply like to consume Nevermore and not contribute to it, then this is not the correct article. Please see the installation docs for more.","sidebar":"defaultSidebar"},"cli":{"id":"cli","title":"CLI Reference","description":"nevermore is the command-line tool that drives the Nevermore workflow: scaffolding new games and packages, installing dependencies, running tests, and deploying places to Roblox via the Open Cloud API. This page is the command reference. For the two deep workflows it links out to their own guides \u2014 Deploying with the CLI and Test Infrastructure.","sidebar":"defaultSidebar"},"conventions/git-workflow":{"id":"conventions/git-workflow","title":"Git Workflow","description":"Git conventions for contributing to Nevermore. These apply to both Luau packages and TypeScript CLI tools.","sidebar":"defaultSidebar"},"conventions/index":{"id":"conventions/index","title":"Conventions","description":"Coding conventions used across the Nevermore codebase. These guides help contributors write code that matches the project style.","sidebar":"defaultSidebar"},"conventions/luau":{"id":"conventions/luau","title":"Luau Conventions","description":"This guide covers how to write Luau code in this project. All code uses --!strict mode, and every file follows consistent patterns for class structure, typing, and naming. These conventions are shared with the Raven companion repo.","sidebar":"defaultSidebar"},"conventions/templates":{"id":"conventions/templates","title":"Template Conventions","description":"Generated and templated files (Luau scripts, Rojo projects, etc.) follow a consistent layout across CLI tools.","sidebar":"defaultSidebar"},"conventions/typescript":{"id":"conventions/typescript","title":"TypeScript Conventions","description":"CLI tools under tools/ are TypeScript ESM packages using yargs for command parsing. This guide covers the patterns and conventions for working on these tools.","sidebar":"defaultSidebar"},"deploy":{"id":"deploy","title":"Deploying with the CLI","description":"nevermore deploy builds a Rojo project, uploads it to a Roblox place via the Open Cloud API, and (optionally) publishes the new version so players see it. nevermore test is built on the same pipeline, so everything that runs in a Roblox place goes through this command.","sidebar":"defaultSidebar"},"gotchas/index":{"id":"gotchas/index","title":"Gotchas","description":"Things that trip people up. Each page collects small tips organized by topic.","sidebar":"defaultSidebar"},"gotchas/tooling":{"id":"gotchas/tooling","title":"Tooling Gotchas","description":"Would this save someone real debugging time? If you wouldn\'t warn a teammate about it, don\'t add it here.","sidebar":"defaultSidebar"},"gotchas/troubleshooting":{"id":"gotchas/troubleshooting","title":"Troubleshooting","description":"Common setup and development issues and how to resolve them.","sidebar":"defaultSidebar"},"ides/index":{"id":"ides/index","title":"IDE Setup","description":"Editor configuration guides for working with Nevermore.","sidebar":"defaultSidebar"},"ides/vscode":{"id":"ides/vscode","title":"VSCode / Cursor","description":"VSCode works with Nevermore relatively easily. We have default extensions.json setup. Follow the general setup tips. These tips should generally work for Cursor and other VS-Code based IDEs.","sidebar":"defaultSidebar"},"install":{"id":"install","title":"Install","description":"Installing Nevermore is easy. Once you have Nevermore set up for your project, it\'s easy to install new packages that are compatible with Nevermore. Generally installing Nevermore can be daunting since it involves a few new pieces of technology. However, this technology is here for a reason, and in general, this installation can be streamlined.","sidebar":"defaultSidebar"},"intro":{"id":"intro","title":"Intro","description":"Here are some quick links to get started with Nevermore:","sidebar":"defaultSidebar"},"testing/index":{"id":"testing/index","title":"Testing","description":"How to write, configure, and run tests for Nevermore packages.","sidebar":"defaultSidebar"},"testing/integration-testing":{"id":"testing/integration-testing","title":"Integration Testing","description":"Per-package unit tests (see Test Infrastructure) verify individual packages in isolation. Integration tests go further \u2014 they deploy a full game that depends on many packages, upload it to Roblox, and run a smoke test to confirm everything boots together. This catches problems that unit tests miss: incompatible package versions, missing dependencies, and broken service initialization order.","sidebar":"defaultSidebar"},"testing/testing":{"id":"testing/testing","title":"Test Infrastructure","description":"Writing tests","sidebar":"defaultSidebar"}}}}')}}]);